import{_ as s,o as n,c as a,a as t}from"./chunks/framework.BHSVNLI7.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"en/tutorials/foundations/qemu-first-boot.md","filePath":"en/tutorials/foundations/qemu-first-boot.md","lastUpdated":null}'),i={name:"en/tutorials/foundations/qemu-first-boot.md"};function o(r,e,l,p,c,d){return n(),a("div",null,[...e[0]||(e[0]=[t(`<h2 id="what-we-re-doing" tabindex="-1">What We&#39;re Doing <a class="header-anchor" href="#what-we-re-doing" aria-label="Permalink to &quot;What We&#39;re Doing&quot;">​</a></h2><p>This is the climax of our entire environment setup—we&#39;re finally going to boot the compiled kernel and the built rootfs. We&#39;ll use QEMU&#39;s <code>virt</code> machine type to boot the ARM64 kernel, then break down the boot log line by line to understand exactly what each output means. Understanding boot logs is a core skill in kernel learning, because when debugging drivers or troubleshooting issues later on, these logs are the primary information you&#39;ll work with.</p><h2 id="what-to-know" tabindex="-1">What to Know <a class="header-anchor" href="#what-to-know" aria-label="Permalink to &quot;What to Know&quot;">​</a></h2><h3 id="qemu-virt-machine-type" tabindex="-1">QEMU virt Machine Type <a class="header-anchor" href="#qemu-virt-machine-type" aria-label="Permalink to &quot;QEMU virt Machine Type&quot;">​</a></h3><p>QEMU supports multiple machine types on the ARM/ARM64 platform, ranging from emulating real development boards (like Raspberry Pi or Versatile Express) to purely virtual machines. We use the <code>virt</code> type, which is QEMU&#39;s recommended virtual platform for ARM64 kernel development. <code>virt</code> doesn&#39;t emulate any real physical SoC; instead, it provides a clean set of VirtIO devices—generic virtualized device interfaces that offer good performance, clean code, and no legacy baggage.</p><p>You can use <code>qemu-system-aarch64 -M help</code> to see all ARM64 machine types supported by QEMU. The list is long, covering everything from various BMC boards to Xilinx Zynq, but we only care about <code>virt</code>.</p><h3 id="boot-command" tabindex="-1">Boot Command <a class="header-anchor" href="#boot-command" aria-label="Permalink to &quot;Boot Command&quot;">​</a></h3><p>The project provides a <a href="./scripts/qemu-run.sh">qemu-run.sh</a> script to simplify QEMU&#39;s boot parameters. It automatically detects the kernel image and rootfs file in the build output directory. Running it is straightforward:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/qemu-run.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The script prints the detected configuration at startup so we can confirm it found the correct files:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[INFO] === QEMU ARM System Emulation ===</span></span>
<span class="line"><span>[INFO] Architecture:     aarch64</span></span>
<span class="line"><span>[INFO] Machine:          virt</span></span>
<span class="line"><span>[INFO] CPU:              cortex-a72</span></span>
<span class="line"><span>[INFO] Memory:           1G</span></span>
<span class="line"><span>[INFO] SMP:              2</span></span>
<span class="line"><span>[INFO] Detected QEMU binary: qemu-system-aarch64</span></span>
<span class="line"><span>[INFO] Auto-detected kernel: .../out/build_latest_arm64/arch/arm64/boot/Image</span></span>
<span class="line"><span>[INFO] Auto-detected initrd: .../out/build_latest_arm64/rootfs.cpio.gz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>The kernel is <code>Image</code> (the ARM64 boot image we compiled in the previous article), the initrd is <code>rootfs.cpio.gz</code> (the BusyBox rootfs we packaged in the article before that), and we don&#39;t need to specify a DTB—the QEMU virt machine automatically generates a Device Tree and passes it to the kernel.</p><p>After booting, press <code>Ctrl+A, X</code> in the QEMU serial terminal to exit.</p><h3 id="boot-log-breakdown" tabindex="-1">Boot Log Breakdown <a class="header-anchor" href="#boot-log-breakdown" aria-label="Permalink to &quot;Boot Log Breakdown&quot;">​</a></h3><p>The kernel boot log is a timeline. The timestamp at the beginning of each line, <code>[0.000000]</code>, represents the seconds elapsed since the kernel started. Let&#39;s break down our actual boot output section by section to understand the different phases of kernel startup.</p><p><strong>Phase 1: Kernel Decompression and Platform Initialization (0.000000 - 0.010000)</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Booting Linux on physical CPU 0x0000000000 [0x410fd083]</span></span>
<span class="line"><span>[    0.000000] Linux version 6.19.9 (charliechen@Charliechen) (aarch64-linux-gnu-gcc (GCC) 15.2.0, GNU ld (GNU Binutils) 2.46.0) #1 SMP PREEMPT Sat May  9 13:22:23 CST 2026</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The first line tells us the kernel is booting on CPU 0. <code>0x410fd083</code> is the CPU&#39;s MIDR (Main ID Register) value, and the QEMU-emulated cortex-a72 corresponds to this ID. The second line is the classic kernel version string, containing the compiler username, compiler version, linker version, SMP/PREEMPT flags, and build time. This information might look like showing off, but it&#39;s crucial for troubleshooting—we need to confirm we&#39;re actually running the kernel we compiled, not some version that came with the system.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Machine model: linux,dummy-virt</span></span>
<span class="line"><span>[    0.000000] efi: UEFI not found.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>linux,dummy-virt</code> is the <code>model</code> property value of the QEMU virt machine in the Device Tree. &quot;UEFI not found&quot; is normal—we didn&#39;t configure a UEFI firmware, so the kernel jumps directly into startup from the bootloader, following the traditional Device Tree boot path.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Kernel command line: console=ttyAMA0,115200 root=/dev/ram0 rdinit=/init</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>These are the boot parameters passed to the kernel. <code>console=ttyAMA0,115200</code> specifies the serial console device as the PL011 UART with a baud rate of 115200; <code>root=/dev/ram0</code> tells the kernel that the root filesystem is on a RAM disk; <code>rdinit=/init</code> specifies the first userspace program the kernel executes inside the initramfs.</p><p><strong>Phase 2: Memory and CPU Initialization (0.000000 - 0.070000)</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Zone ranges:</span></span>
<span class="line"><span>[    0.000000]   DMA      [mem 0x0000000040000000-0x000000007fffffff]</span></span>
<span class="line"><span>[    0.000000]   DMA32    empty</span></span>
<span class="line"><span>[    0.000000]   Normal   empty</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The kernel divides physical memory into different zones. The entire 1GB kernel on ARM64 falls into the DMA zone (0x40000000-0x7FFFFFFF), because our QEMU is configured with 1GB of memory starting at address 0x40000000 (the DRAM base address of the virt machine). The DMA32 and Normal zones are empty because a 1GB address range doesn&#39;t require higher zones.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.065793] Detected PIPT I-cache on CPU1</span></span>
<span class="line"><span>[    0.066669] CPU1: Booted secondary processor 0x0000000001 [0x410fd083]</span></span>
<span class="line"><span>[    0.070450] smp: Brought up 1 node, 2 CPUs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>The SMP (Symmetric Multiprocessing) subsystem brings up the second CPU core. CPU0 is the primary core (boot CPU), which starts working at the very beginning of kernel boot; CPU1 is a secondary core, woken up shortly after by the SMP framework. Both cores are identified as cortex-a72.</p><p><strong>Phase 3: Kernel Subsystem Initialization (0.070000 - 0.500000)</strong></p><p>This is the longest section of the log. The kernel&#39;s various subsystems initialize in a fixed order—memory management, scheduler, timers, interrupt controller, clocksource, device model, network stack, and so on. Each &quot;Registered&quot; or &quot;initialized&quot; represents a subsystem that has completed its initialization.</p><p>A few lines worth noting:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.221730] Serial: AMBA PL011 UART driver</span></span>
<span class="line"><span>[    0.270233] 9000000.pl011: ttyAMA0 at MMIO 0x9000000 (irq = 13, base_baud = 0) is a PL011 rev1</span></span>
<span class="line"><span>[    0.273819] printk: console [ttyAMA0] enabled</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>The PL011 serial driver initializes and registers the <code>ttyAMA0</code> device. The MMIO address <code>0x9000000</code> is the physical address allocated by the QEMU virt machine for the PL011 UART. From this moment on, the output from <code>printk</code> actually appears on our terminal—everything we saw before this was actually stored in the kernel&#39;s log buffer first, and only flushed out together once the serial driver was ready.</p><p><strong>Phase 4: initramfs Decompression and Userspace Startup (0.420000 - 0.990000)</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.428951] Unpacking initramfs...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The kernel begins decompressing our cpio.gz initramfs. It uses the gzip algorithm to decompress, then parses the file list in cpio newc format, creating each file into the rootfs.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.987816] Freeing unused kernel memory: 3264K</span></span>
<span class="line"><span>[    0.989078] Run /init as init process</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>Freeing unused kernel memory</code> is the kernel freeing the memory of the <code>__init</code> section—this code only runs once during the boot phase (such as various <code>__init</code> functions) and is no longer needed after startup, so the kernel reclaims this memory for system use. Then the kernel executes <code>/init</code>, transferring control from kernel space to userspace.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=== PenguinLab Initramfs ===</span></span>
<span class="line"><span>Kernel: 6.19.9</span></span>
<span class="line"><span>Console: /dev/console</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Starting shell...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/bin/sh: can&#39;t access tty; job control turned off</span></span>
<span class="line"><span>~ #</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>This is the output from our <code>/init</code> script. That final <code>can&#39;t access tty; job control turned off</code> is not a fatal error—BusyBox&#39;s shell disables job control (Ctrl+Z, <code>fg</code>/<code>bg</code>, etc.) when there&#39;s no real TTY device, but basic command execution is unaffected.</p><p>At this point, from QEMU loading the kernel image to entering the BusyBox shell, the total time was less than 1 second. This speed is thanks to our streamlined mini config—no unnecessary driver initialization, no waiting for hardware probe timeouts, the entire boot chain is clean and efficient.</p><h2 id="try-it-yourself" tabindex="-1">Try It Yourself <a class="header-anchor" href="#try-it-yourself" aria-label="Permalink to &quot;Try It Yourself&quot;">​</a></h2><ol><li>Run <code>./scripts/qemu-run.sh run</code> and wait to enter the BusyBox shell</li><li>Run <code>uname -a</code> in the shell to confirm the kernel version is 6.19.9 and the architecture is aarch64</li><li>Run <code>cat /proc/cpuinfo</code> to see the CPU information reported by QEMU</li><li>Run <code>cat /proc/meminfo</code> to see the memory usage reported by the kernel</li><li>Run <code>ls /sys/</code> and <code>ls /dev/</code> to confirm that sysfs and devtmpfs are mounted correctly</li><li>Press <code>Ctrl+A, X</code> to exit QEMU</li></ol><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li>scripts/qemu-run.sh — The project&#39;s QEMU boot script; the <code>cmd_run()</code> function shows the complete boot parameter configuration</li><li><a href="https://www.qemu.org/docs/master/system/target-arm.html" target="_blank" rel="noreferrer">QEMU ARM System Emulator Documentation</a> — QEMU&#39;s official ARM/ARM64 emulation reference</li><li><a href="https://lwn.net/Articles/660404/" target="_blank" rel="noreferrer">Speeding up kernel development with QEMU</a> — A classic LWN article on why QEMU is the best companion for kernel development</li></ul>`,44)])])}const m=s(i,[["render",o]]);export{u as __pageData,m as default};
